<template>
    <section>
        <loader :is-visible="isLoading"></loader>

        <div class="col-md-12 p-0 mt-2">
            <div class="ticketsmallfix theme-primary p-actions-expand " style="overflow: visible;">
                <span class="p-name text-white">{{ $t('BulkMoveAdvance') }}</span>
                <span class="p-actions float-right">
                    <a title="View Queue List" href="javascript:;" class="p-action-btn text-white" @click="viewQueueListAction">
                        <em class="fa fa-eye"></em><br /><span>{{ $t('ViewQueueList') }}</span>
                    </a>
                </span>
            </div>
        </div>

        <div class="border p-3 float-left w-100  remove_blackheader">
        <div class="col-lg-12 col-md-12 col-sm-12 mb-3 p-0 downloadsamplefilenew">
        <div data-v-1d6fe1f6="" class="heading-border ">
            <h5 class="h5">
                <span>{{ $t('Search') }}</span>
                <small class="float-right ">
                <a href="https://cogniterblob.blob.core.windows.net/talygen/Billing/BulkMoveSampleFiles/BulkMoveAdvanceSampleFile.xlsx" download="BulkMoveAdvanceSampleFile.xls" class="font-14 font-weight-medium text-success">
                    <em class="fa fa-file-excel mr-2 font-20"></em>{{ $t('DownloadBulkMoveAdvanceSampleFile') }}</a>
                </small>
        </h5>
        </div>
        </div>     
        <dynamic-form ref="dynamicform" lang="en" :buttons="buttons" :schema="FormSchema" v-on:OnSubmit="onSubmit" :mandatorytext="$t('MandatoryString')" :inlinebuttons="true">
            <template v-slot:tgslot-SampleFile="{ data }">
                <div class="col-lg-12 col-xl-12 p-0">
                    <div class="form-group" id="divFiles">                       
                            <div class="input-group mb-3">
                                <div class="form-control">
                                    <span class="text-truncate">Download BulkMoveAdvanceSampleFile.xls</span>
                                </div>
                                <div class="input-group-append">
                                    <a href="https://cogniterblob.blob.core.windows.net/talygen/Billing/BulkMoveSampleFiles/BulkMoveAdvanceSampleFile.xlsx" class="input-group-text" title="Download" checkprivilege="no">
                                        <i class="fa fa-download action-icon"></i>
                                    </a>
                                </div>                           
                        </div>
                    </div>
                </div>
            </template>
        </dynamic-form>
         <!-- <div class="heading-border mt-3">
            <h5 class="h5"><span>{{ $t('List') }}</span></h5>
        </div> -->
        <div class="row mb-2 mt-3">
            <div class="col-12 mb-2">
                <div class="d-inline-block mr-2">
                    <span class="legend-Progress colorboxsquare"></span>{{ $t('InvoiceSentMessageOnBulkMoveAdvance') }}
                </div>
                <div class="d-inline-block mr-2">
                    <span class="legend-ovrdue colorboxsquare"></span>{{ $t('BulkMoveAdvanceSameInvoice') }}
                </div>
            </div>
        </div>

        <tg-list
            :key="reloadkey"
            ref="tgList"
            :listType="['List']"
            :IsShowAction="true"
            :showCheckBox="false"
            ModuleName="BillingValidationData"
            SubModuleCode="BulkMoveAdvance"
            IdentityColumn="COLUMN_ID"
            :HeaderText="$t('BulkMoveAdvance')"
            :ListData="ListingData"
            :HeaderData="Headers"
            :widgets="widgets"
            :HeaderButtons="[]" 
            :TotalRecords="TotalRecords"
            :RenderRowActionMethod="renderActions"
            :ListDataCallBackFunction="FetchBulkMoveAdvanceRecords"
            :SortExp="SortExp"
            :SortBy="SortBy"
            :NorecordfoundText="$t('NoRecordfound')"
            v-on:PagerButtonClick="pagerMethod"
            v-on:HeaderButtonClick="commonHeaderButtonClick"
            v-on:SortdataButtonClick="sortdata"
            :LegendArray="LegendArray"
            v-on:LeftsearchButtonClick="leftCommonSearch"
            v-on:ActionButtonClick="actionButtonClick"
            tableClasses=""
            :SearchFields="false"
            :CurrentPageNumber="PageNumber">
            <template v-slot:slotdata="{ data }" >
                <template v-if="data.column.COLUMN_NAME == 'CLIENT_NAME'">
                   <div>
                    <SearchableSelect
                     :key="data.row.COLUMN_ID + '-client'"
                     v-model="data.row.selectedClients"
                     :items="groupedUtilities"
                     :max-visible-chips="3"
                     :action-buttons="{ selectAll: true, active: true, inactive: true, clear: true }"
                     :item-fields="['text']"
                     :group-fields="['groupText']"
                     :max-render-items="50"
                     :lazy-load="true"
                     placeholder="Select Clients..."
                     :onChange="(value) => onRowClientChange(value, data.row)"
                     :min-search-length="0"
                     :class="{ 'border-danger': data.row.hasErrorClient }"
                     style="min-width: 300px"
                     />
                </div>
                </template>
                <template v-if="data.column.COLUMN_NAME == 'UTILITY'">
                        <select :key="data.row.COLUMN_ID + '-utility'" v-model="data.row.selectedUtilities" name="UTILITY" @change="(event) => onSelectionUtilityChange(event.target.value, data.row)" :class="['form-control', 'ddlfirstfield', { 'border-danger': data.row.hasErrorUtility }]">
                                    <option value="">{{ $t("Select") }}</option>
                                        <option v-for="item in data.row.UtilityOptions" :value="item.value">{{$t(item.text) }}</option>
                                        </select>
                </template>
                <template v-if="data.column.COLUMN_NAME == 'SBA'">
                        <select :key="data.row.COLUMN_ID + '-sba'" v-model="data.row.selectedSba" name="SBA" :class="['form-control', 'ddlfirstfield', { 'border-danger': data.row.hasErrorSba }]">
                                    <option value="">{{ $t("Select") }}</option>
                                        <option v-for="item in data.row.SbaOptions" :value="item.value">{{$t(item.text) }}</option>
                                        </select>
                </template>
                <template v-if="data.column.COLUMN_NAME == 'DIVISION'">
                        <select :key="data.row.COLUMN_ID + '-division'" v-model="data.row.selectedDevision" name="DIVISION" :class="['form-control', 'ddlfirstfield', { 'border-danger': data.row.hasErrorDiv }]">
                                   <option value="">{{ $t("Select") }}</option>
                                       <option v-for="item in data.row.DivisionOptions" :value="item.value">{{$t(item.text) }}</option>
                                       </select>
                </template>
                <template v-if="data.column.COLUMN_NAME == 'INVOICE_NUMBER'">
                        <input :key="data.row.COLUMN_ID + '-invoice'" v-model="data.row.INVOICE_NUMBER" type="text" class="form-control" :class="{ 'border-danger': data.row.hasErrorInvoice }" />
                </template>
            </template>
        </tg-list>
        <div class="modal-footer">
               <button @click="btnUpdateAdvanceClientAndUtility" class="btn btn-success">
                           <em class="fa fa-save pr-2" aria-hidden="true"></em> {{ $t('BulkMove') }}
                     </button>
                  <button @click="Clear" class="btn btn-danger">
                         <em class="fa fa-times pr-2" aria-hidden="true"></em> {{ $t('Cancel') }}
                   </button>
                            </div>

</div>


         <BulkMoveQueue v-if="IsViewQueueList" :ReqFrom="ReqFrom"></BulkMoveQueue>
    </section>
</template>

<script>
import { locateBillingService } from "../../../services/locateBillingService";
import http from "../../../http-common";
  import Schema from "./BulkMoveAdvanceSchema.js";
  import BulkMoveQueue from "../../BillingValidationData/components/BulkMoveQueue.vue";
  import SearchableSelect from '@/components/Common/SearchableSelect.vue';

export default {
    name: "BulkMoveAdvance",
    components: {
        BulkMoveQueue,
        SearchableSelect
    },
    data() {
        return {
            isLoading: false,
            PageSize: 10,
            PageNumber: 1,
            isPaged: 1,
            TotalPages: 0,
            widgets: [],
            LegendArray: [],
            SortBy: '',
            SortExp: '',
            CurrentPage: 1,
            TotalRecords: 0,
            ListingData: [],
            fileData: [],
            Buttons: Schema.buttons,
            leftSearchFields: Schema.leftsearchSchema,
            listActions: Schema.listActions,
            Headers: Schema.headerSchema,
            searchCondition: "",
            selectedClientId: null,
            bulkClientId: null,
            IsViewQueueList: false,
            ReqFrom: 'ADVANCE',
            FormSchema: [{
                layoutType: "triple",
                Data: [
                    {
                        astype: "NormalFileField",
                        label: this.$t('AttachFiles'),
                        name: "Attachment",
                        placeholder: "",
                         validationRules: {
                            "required": true
                        },
                        FieldIndex: 0,
                        config: {
                            maxSize: 5,
                            showSelectedFiles: [],
                            accept: [
                            { fileType: 'xlsx', iconClass: 'fa-file-excel-o' },
                            { fileType: 'xls',  iconClass: 'fa-file-excel-o' },
                            { fileType: 'csv',  iconClass: 'fa-file-text-o' }
                            ],
                            onDeleteSelectedFiles: this.onDeleteSelectedFiles,
                            onChange: this.GetBase64String,
                            showAddIcon: false,
                            onAddButtonClick: '',
                            multiple: false
                        },
                    },
                {
                    astype: "DateRangeField",
                    label: this.$t('Work_Date'),
                    name: "WorkDateFrom",
                    value: "",
                    placeholder: "",
                    config: {
                        format: "MM/DD/YYYY",
                        maxDate: false,
                        onChange: this.setTimerDate,
                         datePickerConfig: {
                                useCurrent: true,
                                showClear: true,
                                showClose: true,
                                allowInputToggle: false,
                                minDate: true,
                                maxDate: true,
                                widgetPositioning: {
                                    horizontal: 'right',
                                    vertical: 'bottom'
                                }
                            },
                            secondDatePickerConfig: {
                                useCurrent: false,
                                showClear: true,
                                showClose: true,
                                allowInputToggle: false,
                                minDate: true,
                                maxDate: true,
                                widgetPositioning: {
                                    horizontal: 'right',
                                    vertical: 'bottom'
                                }
                            },
                    },
                    validationRules: {
                        "required": true
                    },
                },
                {
                    astype: "SlotField",
                    label: this.$t('SampleFile'),
                    name: 'SampleFile',
                    value: "",
                    visibility: false,
                    config: {
                        options: []
                    },
                    placeholder: this.$t('Select'),
                    validationRules: {
                        "required": false,
                        max: 100
                    },
                },
           ],
            }],
            buttons: [{
                type: "submit",
                class: "btn btn-success",
                text: "<i class='fa fa-search pr-2'></i>Search",
            },
            {
                type: "button",
                class: "btn btn-danger",
                text: "<i class='fa fa-refresh pr-2'></i>Clear",
                onClick: this.Clear,
            }],
            reloadkey:0
        };
    },
    created: async function () {
        var vm = this;
        vm.Headers.forEach(element => {
            element.DISPLAY_NAME = vm.$t(element.DISPLAY_NAME);
        }); 
        await vm.fetchclientlist();
    },
    methods: {
         fetchclientlist: function () {
            var vm = this;
            vm.isLoading = true;
            var url = `reqFrom=CUSTOM`;
            locateBillingService.getClientList(url).then(response => {
                vm.isLoading = false;
                vm.clientList = response.data.items;
                vm.groupedUtilities=vm.clientList;
            }).catch(error => {
                vm.isLoading = false;
                vm.clientList = []; 
                vm.groupedUtilities=vm.clientList;
                console.error('Error fetching client list:', error);
            }).finally(() => {
                vm.isLoading = false;
            });
        },
        leftCommonSearch: function (value) {
            this.PageNumber = value.PageNumber;
            this.isPaged = 1;
            if (typeof value.searchCondition != 'undefined') {
                if (value.searchConditionJson != '') {
                    this.searchCondition = value.searchConditionJson;
                } else {
                    this.searchCondition = value.searchCondition || "";
                }
            } else {
                this.searchCondition = "";
            }
            this.FetchBulkMoveAdvanceRecords();
        },
         renderActions: function (row) {
            var self = this;
            let rtnActionArray = [];
            self.listActions.forEach(actionItem => {
                let action = { ...actionItem };
                switch (action.title) {
                    case 'Update':
                        action.isVisible = true;
                        break;
                    default: {
                        action.isVisible = true;
                    }
                }
                rtnActionArray.push(action);
            });
            return rtnActionArray;
        },
        pagerMethod: function (value) {
            this.PageSize = value.PageSize;
            this.PageNumber = value.PageNumber;
            this.FetchBulkMoveAdvanceRecords();
        },
      setTimerDate: function (x, y, z) {
                const vm = this;
                if (!y) return;

                const today = new Date();
                today.setHours(0, 0, 0, 0);

                // 🔹 Preserve existing valid future secondValue
                if (y.secondValue) {
                    const existingSecondDate = vm.parseDateString(y.secondValue);
                    if (existingSecondDate && !isNaN(existingSecondDate.getTime())) {
                        existingSecondDate.setHours(0, 0, 0, 0);
                        // If valid future secondValue → keep it
                        vm.$refs.dynamicform.updateProperty(
                            y.name,
                            "secondValue",
                            vm.$options.filters.formatDateForForm(existingSecondDate)
                        );
                        // Also update minDate based on y.value
                        if (y.value) {
                            vm.$refs.dynamicform.updateProperty(
                                y.name,
                                "config.secondDatePickerConfig.minDate",
                                y.value
                            );
                        }
                        return;
                    }
                }

                // 🔹 If no value, fallback to today
                if (!y.value) y.value = vm.$options.filters.formatDateForForm(today);

                let selectedDate = vm.parseDateString(y.value);
                if (!selectedDate || isNaN(selectedDate.getTime())) {
                    selectedDate = new Date(today);
                }
                selectedDate.setHours(0, 0, 0, 0);

                // 🔹 Compute secondValue
                const secondValue =
                    selectedDate > today
                        ? vm.$options.filters.formatDateForForm(selectedDate)
                        : vm.$options.filters.formatDateForForm(today);

                try {
                    // Update minDate and secondValue
                    vm.$refs.dynamicform.updateProperty(
                        y.name,
                        "config.secondDatePickerConfig.minDate",
                        y.value
                    );

                    vm.$refs.dynamicform.updateProperty(
                        y.name,
                        "secondValue",
                        secondValue
                    );

                    vm.$refs.dynamicform.updateProperty(
                        y.name,
                        "config.datePickerConfig.maxDate",
                        ''
                    );
                } catch (e) {
                    console.error('setTimerDate error:', e);
                }
            },

           parseDateString: function (dateString) {
                if (!dateString) return null;

                // Accept Date object directly
                if (dateString instanceof Date && !isNaN(dateString.getTime())) {
                    return dateString;
                }
                const m = moment(
                    dateString,
                    [
                        moment.ISO_8601, // ISO strings
                        'MM/DD/YYYY',    // US format
                        'DD-MM-YYYY',    // dash format
                        'MM-DD-YYYY',    // optional safety
                        'YY-MM-DD',      // short year
                        'YYYY-MM-DD'
                    ],
                    true // strict parsing
                );
                if (!m.isValid()) return null;
                return m.toDate();
            },
       actionButtonClick: function (callbackfunction, item) {
           switch (callbackfunction) {
               case 'EditRecord':
                   this.btnTempChangeSubmitInvoice(item);
                   break;
           }
       },
       btnTempChangeSubmitInvoice: function (item) {
        var vm = this;
        vm.isLoading = true;
        let clientId = vm.bulkClientId || "";
        if (!clientId) {
            clientId = item.selectedClients || "";
        }
        let utilityId = item.selectedUtilities || "";
        let sbaId = item.selectedSba || "";
        let divId = item.selectedDevision || "";
        let invoiceNumber = item.INVOICE_NUMBER || "";
        let batchIdAdvance = vm.BulkMoveBatchId;
        let processBatchId = item.NEW_BATCH_ID;
        let msg = "";
        // Reset errors
        vm.$set(item, 'hasErrorClient', false);
        vm.$set(item, 'hasErrorUtility', false);
        vm.$set(item, 'hasErrorSba', false);
        vm.$set(item, 'hasErrorDiv', false);
        vm.$set(item, 'hasErrorInvoice', false);
        if (invoiceNumber) {
        } else {
            if (!clientId) {
                msg += "no";
                vm.$set(item, 'hasErrorClient', true);
            }
            if (!utilityId) {
                msg += "no";
                vm.$set(item, 'hasErrorUtility', true);
            }
            if (!sbaId) {
                msg += "no";
                vm.$set(item, 'hasErrorSba', true);
            }
            if (!divId) {
                msg += "no";
                vm.$set(item, 'hasErrorDiv', true);
            }
        }
        
        if (msg.length > 0) {
            vm.isLoading = false;
            vm.ShowAlert('Correct highlighted errors', "warning", true, vm.$t("Alert"));
            return false;
        }
        
        let postData = { 
            ClientId: clientId, 
            UtilityId: utilityId, 
            SbaId: sbaId, 
            DivId: divId, 
            BatchIdAdvance: batchIdAdvance, 
            ProcessBatchId: processBatchId, 
            InvoiceNumber: invoiceNumber 
        };
        
        locateBillingService.BulkMoveAdvancePostData(postData).then(response => {
            vm.isLoading = false;
            if (response.data.msg == 'Success') {
                vm.FetchBulkMoveAdvanceRecords();
                vm.ShowAlert(vm.$t('RecordUpdatedSuccessfully'), "success", true, vm.$t("Alert"));
            } else {
                vm.ShowAlert(response.data.msg || 'Unknown error', "failure", true, vm.$t("Alert"));
            }
        }).catch(function (error) {
            console.error(error);
            vm.isLoading = false;
            vm.ShowAlert('Error occurred', "failure", true, vm.$t("Alert"));
        });
    },
       btnUpdateAdvanceClientAndUtility: function () {
           var vm = this;
           var msg = 'Are you sure you want to perform bulk move?'; // Simplified
           vm.confirmR(msg, true, vm.$t('BulkMove'), function () {
               vm.isLoading = true;
               var postData = {
                   WorkDateFrom: vm.WorkDateFrom,
                   WorkDateTo: vm.WorkDateTo,
                   BatchIdAdvance: vm.BulkMoveBatchId
               };
               locateBillingService.UpdateAdvanceBulkMoveLineIds(postData).then(response => {
                   vm.isLoading = false;
                   if (response.data.flag == "success" && response.data.statusCode != -11) {
                       if (response.data.statusCode == 0) {
                           vm.ShowAlert(response.data.msg, "success", true, vm.$t("Alert"));
                           vm.FetchBulkMoveAdvanceRecords();
                       } else if (response.data.statusCode == -12) {
                           vm.ShowAlert(response.data.msg, "failure", true, vm.$t("Alert"));
                           vm.FetchBulkMoveAdvanceRecords();
                       }
                       if (response.data.bulkMoveResult != null) {
                           if (response.data.statusCode == 101) {
                               vm.ShowAlert('No billing rule found', "warning", true, vm.$t("Alert"));
                           }
                       }
                   } else if (response.data.flag == "success" && response.data.statusCode == -11) {
                       vm.ShowAlert('Bulk move already in queue', "failure", true, vm.$t("Alert"));
                   } else {
                       vm.ShowAlert(response.data.msg || 'Error', "failure", true, vm.$t("Alert"));
                   }
               }).catch(error => {
                   vm.isLoading = false;
                   vm.ShowAlert('Error while processing request', "failure", true, vm.$t("Alert"));
               });
           });
       },
        commonHeaderButtonClick: function (event) {
            switch (event.callbackfunction) {
                case "viewQueueListAction":
                    this.viewQueueListAction();
                    break;
            }
        },
        sortdata: function (sortBy) {
            this.SortBy = sortBy;
            if (this.SortExp == "") {
                this.SortExp = "ASC";
            } else if (this.SortExp == "ASC") {
                this.SortExp = "DESC";
            } else {
                this.SortExp = "ASC";
            }
            this.FetchBulkMoveAdvanceRecords();
        },
        FetchBulkMoveAdvanceRecords: function () {
            var vm = this;
            vm.isLoading = true;
            var filePath = vm.filePath;
            var url = `pageSize=${vm.PageSize}&pageNum=${vm.PageNumber}&sortBy=${vm.SortBy}&sortExp=${vm.SortExp}&workDateFrom=${vm.WorkDateFrom}&workDateTo=${vm.WorkDateTo}` +
                `&filepath=${encodeURIComponent(filePath)}` +
                `&filename=${encodeURIComponent('BulkMove_Advance_SampleFile.xlsx')}` +
                `&fileNewname=${encodeURIComponent('758499944.xlsx')}`;

            if (vm.searchCondition) {
                url += `&${vm.searchCondition}`;
            }
            locateBillingService.GetBulkMoveAdvanceListing(url).then((response) => {
                vm.isLoading = false;
                if (response.data.result) {
                    vm.ListingData = JSON.parse(response.data.result);
                    vm.BulkMoveBatchId = response.data.bulkMoveBatchId;
                }
                if (vm.ListingData && vm.ListingData.length > 0) {
                    vm.ListingData.forEach((item, index) => {
                        if (item.DATEOFINV) {
                            item.DATEOFINV = new Date(item.DATEOFINV);
                        }
                        if (item.DATEOFWORK) {
                            item.DATEOFWORK = new Date(item.DATEOFWORK);
                        }
                        item.selectedUtilities = '';
                        item.selectedSba = '';
                        item.selectedDevision = '';
                        item.selectedClients='';
                        item.UtilityOptions = [];
                        item.SbaOptions = [];
                        item.DivisionOptions = [];
                    });
                    vm.TotalRecords = vm.ListingData[0].TOTAL_RECORDS || vm.ListingData[0].TOTALRECORDS || 0;
                    vm.TotalPages = Math.ceil(vm.TotalRecords / vm.PageSize);
                    vm.CurrentPage = vm.PageNumber;
                } else {
                    vm.ListingData = [];
                    vm.TotalRecords = 0;
                }
            })
            setTimeout(() => {
                vm.isLoading = false;
                vm.ListingData = [];
                vm.TotalRecords = 0;
            }, 100);
        },
        formatDate(dateString) {
            if (!dateString) return '';
            if (dateString instanceof Date) {
                return dateString.toLocaleDateString();
            }
            const date = new Date(dateString);
            return date.toLocaleDateString();
        },
        formatCurrency(value) {
            if (!value && value !== 0) return '0.00';
            return parseFloat(value).toFixed(2);
        },
        selectAllLineItems() {
            // Select all checkboxes in the listing, excluding the header select all checkbox
            $('.chkItems').not("[id^='chkAll_0']").prop('checked', true);
        },
        GetBase64String: function (evt) {
            try {
                var vm = this;
                vm.fileData = [];
                var files = evt.target.files; // FileList object
                vm.attachmentName = files[0].name;
                for (var i = 0; i < files.length; i++) {
                    var f = files[i];
                    var reader = new FileReader();
                    // Closure to capture the file information.
                    reader.onload = (function (theFile) {
                        return function (e) {
                            var binaryData = e.target.result;
                            //Converting Binary Data to base 64
                            var base64StringEncoded = window.btoa(binaryData);
                            vm.base64String = base64StringEncoded;
                            //showing file converted to base64

                            var fileName = f.name;
                            //vm.fileName = fileName;
                            var n = fileName.lastIndexOf(".");
                            var extensionName = fileName.substring(n + 1, fileName.length);

                            //vm.fileExt += "." + extensionName;
                            var attachemnetMime = '{"ContentType":"' + f.type + '","Size":"' + f.size + '","Extension":"' + extensionName + '"}';
                            var fileSize = f.size;
                            //vm.fileSize = fileSize;
                             var fileObj = {
                                attachement_mime: attachemnetMime,
                                fileName: fileName,
                                userId: vm.GetUserInfo.ID,
                                companyId: vm.GetUserInfo.CompanyId,
                                id: 0,
                                moduleName: "initialsetup",
                                subModuleCode: "BulkUploaad",
                                containerName: vm.GetUserInfo.ContainerName,
                                base64String: base64StringEncoded,
                                attachement_path: ''
                            };

                            vm.fileData.push(fileObj);
                        };
                    })(f);
                    // Read in the image file as a data URL.
                    reader.readAsBinaryString(f);
                }
            }
            catch (ex) {
            }
        },
        async onSubmit(formfields, val) {
            var vm = this;
            vm.isLoading =true;
            var FromDate = vm.$refs.dynamicform.getPropertyValue("WorkDateFrom", "value");
            var ToDate = vm.$refs.dynamicform.getPropertyValue("WorkDateFrom", "secondValue");
            vm.WorkDateFrom = vm.$options.filters.formatDatee(FromDate);
            vm.WorkDateTo = vm.$options.filters.formatDatee(ToDate);
              let obj = {
                    file_Name: this.fileData[0].fileName,
                    attachment: JSON.stringify(this.fileData)
                };
                let formData = new FormData();
                formData.append("postString", JSON.stringify(obj));
                const response = await locateBillingService.UploadFile(formData);
                if (response.data && response.data.length > 0) {
                    if (response.data[0].Name.length > 0) {
                        vm.filePath = response.data[0].Name;
                    }
                }
                var filePath = vm.filePath;
                var url = `pageSize=${vm.PageSize}&pageNum=${vm.PageNumber}&sortBy=${vm.SortBy}&sortExp=${vm.SortExp}&workDateFrom=${vm.WorkDateFrom}&workDateTo=${vm.WorkDateTo}` +
                `&filepath=${encodeURIComponent(filePath)}` +
                `&filename=${encodeURIComponent('BulkMove_Advance_SampleFile.xlsx')}` +
                `&fileNewname=${encodeURIComponent('758499944.xlsx')}`;

            if (vm.searchCondition) {
                url += `&${vm.searchCondition}`;
            }
            locateBillingService.GetBulkMoveAdvanceListing(url).then((response) => {
                vm.isLoading = false;
                if (response.data.result) {
                    vm.ListingData = JSON.parse(response.data.result);
                    vm.BulkMoveBatchId = response.data.bulkMoveBatchId;
                }
                  if (vm.ListingData && vm.ListingData.length > 0) {
                    vm.ListingData.forEach((item, index) => {
                        item.selectedUtilities = '';
                        item.selectedSba = '';
                        item.selectedDevision = '';
                        item.selectedClients='';
                        item.UtilityOptions = [];
                        item.SbaOptions = [];
                        item.DivisionOptions = [];
                    });
                    vm.TotalRecords = vm.ListingData[0].TOTAL_RECORDS || vm.ListingData[0].TOTALRECORDS || 0;
                    vm.TotalPages = Math.ceil(vm.TotalRecords / vm.PageSize);
                    vm.CurrentPage = vm.PageNumber;
                } else {
                    vm.ListingData = [];
                    vm.TotalRecords = 0;
                }
            })
        },
        viewQueueListAction() {
            var vm = this;
            vm.IsViewQueueList = !vm.IsViewQueueList;
        },
        onDeleteSelectedFiles: function () {
            // Handle file deletion if needed
        },
        Clear: function () {
            var vm = this;
            vm.FormSchema[0].Data.forEach(field => {
                    field.value = "";
            });
            vm.ListingData=[];
            vm.fileData = [];
            vm.$refs.dynamicform.UpdateKeyValue();
        },
        async onSelectionUtilityChange(value, row) {
            var vm = this;
            vm.UtilityId = value;
            var index = vm.ListingData.indexOf(row);
            await vm.fetchSbaForRow(index, value);
            await vm.fetchDivisionForRow(index, value);
        },
         onRowClientChange(value, row) {
            var vm = this;
            var index = vm.ListingData.indexOf(row);
            vm.$set(vm.ListingData[index], 'selectedClients', value);
            vm.selectedClientId=value;
            var url = `clientId=${value}&configId=&reqFrom=&clientIds=`;
            locateBillingService.getUtilityList(url).then(response => {
                let SelectedUtilityList = [];
                var UtilityList = response.data;
                if (UtilityList != null) {
                    UtilityList.forEach(item => {
                        let obj = {
                            text: item.UTILITY_NAME,
                            value: item.UTILITY_ID
                        };
                        SelectedUtilityList.push(obj);
                    });
                    vm.$set(vm.ListingData[index], 'UtilityOptions', SelectedUtilityList);
                    vm.reloadkey++;
                }
            }).catch(error => {
                vm.$set(vm.ListingData[index], 'UtilityOptions', []);
            });
        },
        fetchSbaForRow(index, utilityId) {
            var vm = this;
            var url = `utilityId=${utilityId}`;
            locateBillingService.GetSbaIdListByUtilityId(url).then(response => {
                let SbaList = [];
                var sbaData = response.data;
                if (sbaData != null) {
                    sbaData.forEach(item => {
                        let obj = {
                            text: item.NAME,
                            value: item.SBA_ID
                        };
                        SbaList.push(obj);
                    });
                    vm.$set(vm.ListingData[index], 'SbaOptions', SbaList);
                    vm.reloadkey++;
                }
            }).catch(error => {
                vm.$set(vm.ListingData[index], 'SbaOptions', []);
            });
        },
        fetchDivisionForRow(index, utilityId) {
            var vm = this;
             var url = `clientId=${vm.selectedClientId}&utilityIds=${utilityId}`;
            locateBillingService.LoadClientDivisionListByUtilityIds(url).then(response => {
                let DivisionList = [];
                var divisionData = response.data;
                if (divisionData != null) {
                    divisionData.forEach(item => {
                        let obj = {
                            text: item.NAME,
                            value: item.VALUE
                        };
                        DivisionList.push(obj);
                    });
                    vm.$set(vm.ListingData[index], 'DivisionOptions', DivisionList);
                    vm.reloadkey++;
                }
            }).catch(error => {
                vm.$set(vm.ListingData[index], 'DivisionOptions', []);
            });
        }
    }
}
</script>

